  3→import { useRef, useEffect, useState, forwardRef, useImperativeHandle } from 'react'
  4→import type { Quote } from '@/types'
  5→
  6→// ── Types ─────────────────────────────────────────────────────────────────────
  7→
  8→export interface EditorHandle {
  9→  getCursorOffset(): number
 10→}
 11→
 12→interface Props {
 13→  value: string
 14→  onChange: (value: string) => void
 15→  className?: string
 16→  textareaRef?: React.RefObject<HTMLTextAreaElement | null>
 17→  quotes?: Quote[]
 18→}
 19→
 20→interface PopoverState {
 21→  quoteId: string
 22→  chipOffset: number
 23→  x: number
 24→  y: number
 25→  confirming: boolean
 26→}
 27→
 28→// ── Chip styles (inline to avoid Tailwind purge) ──────────────────────────────
 29→
 30→const CHIP_STYLE = [
 31→  'display:inline-flex',
 32→  'align-items:center',
 33→  'justify-content:center',
 34→  'min-width:18px',
 35→  'height:18px',
 36→  'padding:0 4px',
 37→  'border-radius:4px',
 38→  'background:#fef3c7',
 39→  'color:#b45309',
 40→  'border:1px solid #fde68a',
 41→  'font-size:9px',
 42→  'font-weight:700',
 43→  'cursor:pointer',
 44→  'user-select:none',
 45→  'margin:0 2px',
 46→  'vertical-align:middle',
 47→  'flex-shrink:0',
 48→  'line-height:1',
 49→].join(';')
 50→
 51→// ── Serialization ─────────────────────────────────────────────────────────────
 52→
 53→const QUOTE_RE = /\[quote:([0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12})\]/g
 54→
 55→function escapeHtml(s: string): string {
 56→  return s.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;')
 57→}
 58→
 59→/**
 60→ * Convert a [quote:id] serialized string to contenteditable innerHTML.
 61→ * Newlines → <br>; [quote:uuid] tokens → non-editable Q chip spans.
 62→ */
 63→function toHtml(text: string): string {
 64→  const parts = text.split(QUOTE_RE)
 65→  let html = ''
 66→  for (let i = 0; i < parts.length; i++) {
 67→    if (i % 2 === 0) {
 68→      html += escapeHtml(parts[i]).replace(/\n/g, '<br>')
 69→    } else {
 70→      html += `<span style="${CHIP_STYLE}" contenteditable="false" draggable="true" data-quote-id="${parts[i]}">Q</span>`
 71→    }
 72→  }
 73→  return html
 74→}
 75→
 76→/**
 77→ * Walk the contenteditable DOM and return the [quote:id] serialized string.
 78→ * <br> → '\n'; chip spans → [quote:id]; browser-inserted DIVs → '\n' prefix.
 79→ */
 80→function toText(root: Node): string {
 81→  let text = ''
 82→  for (const node of root.childNodes) {
 83→    if (node.nodeType === Node.TEXT_NODE) {
 84→      text += node.textContent ?? ''
 85→    } else if (node.nodeType === Node.ELEMENT_NODE) {
 86→      const el = node as HTMLElement
 87→      if (el.dataset.quoteId) {
 88→        text += `[quote:${el.dataset.quoteId}]`
 89→      } else if (el.tagName === 'BR') {
 90→        text += '\n'
 91→      } else if (el.tagName === 'DIV' || el.tagName === 'P') {
 92→        // Browser wraps new lines in block elements (Chrome) — add newline prefix
 93→        if (node.previousSibling) text += '\n'
 94→        text += toText(el)
 95→      } else {
 96→        text += toText(el)
 97→      }
 98→    }
 99→  }
100→  return text
101→}
102→
103→// ── Cursor offset helpers ─────────────────────────────────────────────────────
104→
105→/** Serialized character length of a single DOM node. */
106→function nodeLen(node: Node): number {
107→  if (node.nodeType === Node.TEXT_NODE) return node.textContent?.length ?? 0
108→  const el = node as HTMLElement
109→  if (el.dataset?.quoteId) return `[quote:${el.dataset.quoteId}]`.length
110→  if (el.tagName === 'BR') return 1
111→  let n = 0
112→  for (const child of el.childNodes) n += nodeLen(child)
113→  return n
114→}
115→
116→/** Compute the serialized character offset for a given DOM Range. */
117→function getOffsetFromRange(div: HTMLElement, range: Range): number {
118→  // Cursor anchored directly on the div (between child elements)
119→  if (range.startContainer === div) {
120→    let off = 0
121→    for (let i = 0; i < range.startOffset; i++) off += nodeLen(div.childNodes[i])
122→    return off
123→  }
124→
125→  let offset = 0
126→  let found = false
127→
128→  function walk(node: Node): void {
129→    if (found) return
130→    if (node === range.startContainer) {
131→      offset += range.startOffset
132→      found = true
133→      return
134→    }
135→    if (node.nodeType === Node.TEXT_NODE) {
136→      offset += node.textContent?.length ?? 0
137→    } else {
138→      const el = node as HTMLElement
139→      if (el.dataset?.quoteId) {
140→        offset += `[quote:${el.dataset.quoteId}]`.length
141→      } else if (el.tagName === 'BR') {
142→        offset += 1
143→      } else {
144→        for (const child of el.childNodes) {
145→          walk(child)
146→          if (found) return
147→        }
148→      }
149→    }
150→  }
151→
152→  for (const child of div.childNodes) {
153→    walk(child)
154→    if (found) break
155→  }
156→  return offset
157→}
158→
159→/**
160→ * Return the cursor's position as an offset in the serialized (text) string.
161→ * Quote chips count as their full [quote:uuid] token length (~44 chars).
162→ */
163→function getOffset(div: HTMLElement): number {
164→  const sel = window.getSelection()
165→  if (!sel || sel.rangeCount === 0) return 0
166→  return getOffsetFromRange(div, sel.getRangeAt(0))
167→}
168→
169→/** Return the serialized character offset marking the start of a given child node. */
170→function getNodeOffset(div: HTMLElement, targetNode: Node): number {
171→  let offset = 0
172→  let found = false
173→
174→  function walk(node: Node): void {
175→    if (found) return
176→    if (node === targetNode) { found = true; return }
177→    if (node.nodeType === Node.TEXT_NODE) {
178→      offset += node.textContent?.length ?? 0
179→    } else {
180→      const el = node as HTMLElement
181→      if (el.dataset?.quoteId) {
182→        offset += `[quote:${el.dataset.quoteId}]`.length
183→      } else if (el.tagName === 'BR') {
184→        offset += 1
185→      } else {
186→        for (const child of el.childNodes) {
187→          walk(child)
188→          if (found) return
189→        }
190→      }
191→    }
192→  }
193→
194→  for (const child of div.childNodes) {
195→    walk(child)
196→    if (found) break
197→  }
198→  return offset
199→}
200→
201→/**
202→ * Place the cursor at the given offset in the serialized string space.
203→ */
204→function setOffset(div: HTMLElement, target: number): void {
205→  let remaining = target
206→  let placed = false
207→
208→  function placeCursor(node: Node, off: number): void {
209→    const range = document.createRange()
210→    range.setStart(node, off)
211→    range.collapse(true)
212→    window.getSelection()?.removeAllRanges()
213→    window.getSelection()?.addRange(range)
214→    placed = true
215→  }
216→
217→  function walk(node: Node): void {
218→    if (placed) return
219→    if (node.nodeType === Node.TEXT_NODE) {
220→      const len = node.textContent?.length ?? 0
221→      if (remaining <= len) { placeCursor(node, remaining); return }
222→      remaining -= len
223→    } else {
224→      const el = node as HTMLElement
225→      if (el.dataset?.quoteId) {
226→        const len = `[quote:${el.dataset.quoteId}]`.length
227→        if (remaining < len) {
228→          // Place cursor immediately after the chip
229→          const siblings = Array.from(el.parentNode!.childNodes)
230→          placeCursor(el.parentNode!, siblings.indexOf(el as ChildNode) + 1)
231→          return
232→        }
233→        remaining -= len
234→      } else if (el.tagName === 'BR') {
235→        if (remaining === 0) {
236→          placeCursor(div, Array.from(div.childNodes).indexOf(el as ChildNode))
237→          return
238→        }
239→        remaining -= 1
240→      } else {
241→        for (const child of el.childNodes) {
242→          walk(child)
243→          if (placed) return
244→        }
245→      }
246→    }
247→  }
248→
249→  for (const child of div.childNodes) {
250→    walk(child)
251→    if (placed) break
252→  }
253→
254→  if (!placed) {
255→    const range = document.createRange()
256→    range.selectNodeContents(div)
257→    range.collapse(false)
258→    window.getSelection()?.removeAllRanges()
259→    window.getSelection()?.addRange(range)
260→  }
261→}
262→
263→// ── Outline level logic ───────────────────────────────────────────────────────
264→
265→function romanToInt(r: string): number {
266→  const vals: Record<string, number> = {
267→    i: 1, v: 5, x: 10, l: 50, c: 100, d: 500, m: 1000,
268→    I: 1, V: 5, X: 10, L: 50, C: 100, D: 500, M: 1000,
269→  }
270→  let total = 0
271→  const s = r.toLowerCase()
272→  for (let i = 0; i < s.length; i++) {
273→    const cur = vals[s[i]] ?? 0
274→    const next = vals[s[i + 1]] ?? 0
275→    total += cur < next ? -cur : cur
276→  }
277→  return total
278→}
279→
280→function intToRoman(num: number, upper = true): string {
281→  const vals = [1000, 900, 500, 400, 100, 90, 50, 40, 10, 9, 5, 4, 1]
282→  const syms = upper
283→    ? ['M', 'CM', 'D', 'CD', 'C', 'XC', 'L', 'XL', 'X', 'IX', 'V', 'IV', 'I']
284→    : ['m', 'cm', 'd', 'cd', 'c', 'xc', 'l', 'xl', 'x', 'ix', 'v', 'iv', 'i']
285→  let result = ''
286→  for (let i = 0; i < vals.length; i++) {
287→    while (num >= vals[i]) { result += syms[i]; num -= vals[i] }
288→  }
289→  return result
290→}
291→
292→function incrementRoman(current: string): string {
293→  return intToRoman(romanToInt(current) + 1, true) + '. '
294→}
295→
296→function incrementLowerRoman(current: string): string {
297→  return intToRoman(romanToInt(current) + 1, false) + '. '
298→}
299→
300→interface Level {
301→  pattern: RegExp
302→  nextFn: (current: string) => string
303→}
304→
305→const OUTLINE_LEVELS: Level[] = [
306→  { pattern: /^((?:X{0,3})(?:IX|IV|V?I{0,3}))\.\s*/, nextFn: incrementRoman },
307→  { pattern: /^([A-Z])\.\s*/, nextFn: (c) => String.fromCharCode(c.charCodeAt(0) + 1) + '. ' },
308→  { pattern: /^(\d+)\.\s*/, nextFn: (c) => (parseInt(c) + 1) + '. ' },
309→  { pattern: /^([a-z])\.\s*/, nextFn: (c) => String.fromCharCode(c.charCodeAt(0) + 1) + '. ' },
310→  { pattern: /^((?:x{0,3})(?:ix|iv|v?i{0,3}))\.\s*/, nextFn: incrementLowerRoman },
311→]
312→
313→function getIndent(line: string): number {
314→  let count = 0
315→  for (const ch of line) {
316→    if (ch === '\t') count++
317→    else break
318→  }
319→  return count
320→}
321→
322→function getNextPrefix(lines: string[], currentLineIndex: number, indent: number): string {
323→  const indentStr = '\t'.repeat(indent)
324→  const levelIdx = indent % OUTLINE_LEVELS.length
325→  for (let i = currentLineIndex - 1; i >= 0; i--) {
326→    const stripped = lines[i].slice(indent)
327→    if (getIndent(lines[i]) === indent && stripped.length > 0) {
328→      const level = OUTLINE_LEVELS[levelIdx]
329→      const m = stripped.match(level.pattern)
330→      if (m) return indentStr + level.nextFn(m[1])
331→      break
332→    }
333→  }
334→  const firstPrefixes = ['I. ', 'A. ', '1. ', 'a. ', 'i. ']
335→  return indentStr + firstPrefixes[levelIdx]
336→}
337→
338→// ── Component ─────────────────────────────────────────────────────────────────
339→
340→const OutlineEditor = forwardRef<EditorHandle, Props>(function OutlineEditor(
341→  { value, onChange, className, quotes = [] }: Props,
342→  ref,
343→) {
344→  const divRef = useRef<HTMLDivElement>(null)
345→
346→  useImperativeHandle(ref, () => ({
347→    getCursorOffset: () => divRef.current ? getOffset(divRef.current) : 0,
348→  }))
349→  const popoverRef = useRef<HTMLDivElement>(null)
350→  const [popover, setPopover] = useState<PopoverState | null>(null)
351→
352→  // Sync external value changes → innerHTML.
353→  // Only updates when the serialized content actually differs, so normal
354→  // keystrokes (which round-trip through onChange → value) are no-ops here.
355→  useEffect(() => {
356→    const div = divRef.current
357→    if (!div) return
358→    if (toText(div) === value) return
359→    div.innerHTML = toHtml(value)
360→  }, [value])
361→
362→  // Close popover when clicking outside it
363→  useEffect(() => {
364→    if (!popover) return
365→    function onDown(e: MouseEvent) {
366→      if (popoverRef.current && !popoverRef.current.contains(e.target as Node)) {
367→        setPopover(null)
368→      }
369→    }
370→    document.addEventListener('mousedown', onDown)
371→    return () => document.removeEventListener('mousedown', onDown)
372→  }, [popover])
373→
374→  // Serialize DOM → string on every browser-driven mutation
375→  function handleInput() {
376→    const div = divRef.current
377→    if (!div) return
378→    onChange(toText(div))
379→  }
380→
381→  // Intercept paste and insert as plain text only
382→  function handlePaste(e: React.ClipboardEvent<HTMLDivElement>) {
383→    e.preventDefault()
384→    const text = e.clipboardData.getData('text/plain')
385→    document.execCommand('insertText', false, text)
386→  }
387→
388→  // Chip click → popover; other clicks → close popover
389→  function handleClick(e: React.MouseEvent<HTMLDivElement>) {
390→    const target = e.target as HTMLElement
391→    if (target.dataset.quoteId) {
392→      e.preventDefault()
393→      const rect = target.getBoundingClientRect()
394→      const chipOffset = divRef.current ? getNodeOffset(divRef.current, target) : 0
395→      setPopover({ quoteId: target.dataset.quoteId, chipOffset, x: rect.left, y: rect.bottom + 6, confirming: false })
396→    } else {
397→      setPopover(null)
398→    }
399→  }
400→
401→  // Drag Q chip to reorder
402→  function handleDragStart(e: React.DragEvent<HTMLDivElement>) {
403→    const target = e.target as HTMLElement
404→    if (target.dataset?.quoteId) {
405→      e.dataTransfer.setData('text/x-quote-id', target.dataset.quoteId)
406→      e.dataTransfer.effectAllowed = 'move'
407→    }
408→  }
409→
410→  function handleDragOver(e: React.DragEvent<HTMLDivElement>) {
411→    if (e.dataTransfer.types.includes('text/x-quote-id')) {
412→      e.preventDefault()
413→      e.dataTransfer.dropEffect = 'move'
414→    }
415→  }
416→
417→  function handleDrop(e: React.DragEvent<HTMLDivElement>) {
418→    const quoteId = e.dataTransfer.getData('text/x-quote-id')
419→    if (!quoteId || !divRef.current) return
420→    e.preventDefault()
421→    const div = divRef.current
422→    const text = toText(div)
423→    const token = `[quote:${quoteId}]`
424→    const originalPos = text.indexOf(token)
425→    if (originalPos === -1) return
426→
427→    // Resolve drop caret position from mouse coordinates
428→    let dropRange: Range | null = null
429→    if (typeof document.caretRangeFromPoint === 'function') {
430→      dropRange = document.caretRangeFromPoint(e.clientX, e.clientY)
431→    } else {
432→      type CaretPos = { offsetNode: Node; offset: number }
433→      const pos = (document as unknown as { caretPositionFromPoint?: (x: number, y: number) => CaretPos | null })
434→        .caretPositionFromPoint?.(e.clientX, e.clientY) ?? null
435→      if (pos) {
436→        dropRange = document.createRange()
437→        dropRange.setStart(pos.offsetNode, pos.offset)
438→      }
439→    }
440→    if (!dropRange) return
441→
442→    let dropOffset = getOffsetFromRange(div, dropRange)
443→    // Remove chip from serialized text, then adjust drop offset
444→    const textWithout = text.slice(0, originalPos) + text.slice(originalPos + token.length)
445→    if (dropOffset > originalPos) {
446→      dropOffset = Math.max(originalPos, dropOffset - token.length)
447→    }
448→    dropOffset = Math.max(0, Math.min(dropOffset, textWithout.length))
449→    const newText = textWithout.slice(0, dropOffset) + token + textWithout.slice(dropOffset)
450→    div.innerHTML = toHtml(newText)
451→    onChange(newText)
452→    setOffset(div, dropOffset + token.length)
453→  }
454→
455→  // Remove only the specific chip that was clicked (matched by offset, falling back to first occurrence)
456→  function handleDeleteChip(quoteId: string, chipOffset: number) {
457→    const div = divRef.current
458→    if (!div) return
459→    const text = toText(div)
460→    const token = `[quote:${quoteId}]`
461→    const pos = text.slice(chipOffset, chipOffset + token.length) === token
462→      ? chipOffset
463→      : text.indexOf(token)
464→    if (pos === -1) { setPopover(null); return }
465→    const newText = text.slice(0, pos) + text.slice(pos + token.length)
466→    div.innerHTML = toHtml(newText)
467→    onChange(newText)
468→    setPopover(null)
469→  }
470→
471→  // Enter + Tab: outline logic ported from the original textarea implementation,
472→  // rewritten to use getOffset/setOffset instead of selectionStart/selectionEnd.
473→  function handleKeyDown(e: React.KeyboardEvent<HTMLDivElement>) {
474→    const div = divRef.current
475→    if (!div) return
476→
477→    if (e.key === 'Enter' && !e.shiftKey) {
478→      e.preventDefault()
479→      const text = toText(div)
480→      const start = getOffset(div)
481→      const before = text.slice(0, start)
482→      const after = text.slice(start)
483→      const lines = before.split('\n')
484→      const currentLine = lines[lines.length - 1]
485→      const indent = getIndent(currentLine)
486→      const strippedCurrent = currentLine.slice(indent)
487→      const levelIdx = indent % OUTLINE_LEVELS.length
488→      const level = OUTLINE_LEVELS[levelIdx]
489→      const m = strippedCurrent.match(level.pattern)
490→
491→      let newText: string
492→      let newPos: number
493→
494→      if (m && strippedCurrent.length > m[0].length) {
495→        // Line has content after the prefix → continue with next prefix
496→        const newPrefix = getNextPrefix(lines, lines.length, indent)
497→        newText = before + '\n' + newPrefix + after
498→        newPos = start + 1 + newPrefix.length
499→      } else if (m && strippedCurrent.length === m[0].length) {
500→        // Empty prefix line → strip prefix, just insert newline
501→        const newBefore = before.slice(0, before.length - currentLine.length)
502→        newText = newBefore + '\n' + after
503→        newPos = newBefore.length + 1
504→      } else {
505→        // Plain line → preserve indent only
506→        const newPrefix = '\t'.repeat(indent)
507→        newText = before + '\n' + newPrefix + after
508→        newPos = start + 1 + newPrefix.length
509→      }
510→
511→      div.innerHTML = toHtml(newText)
512→      onChange(newText)
513→      setOffset(div, newPos)
514→      return
515→    }
516→
517→    if (e.key === 'Tab') {
518→      e.preventDefault()
519→      const text = toText(div)
520→      const start = getOffset(div)
521→      const before = text.slice(0, start)
522→      const after = text.slice(start)
523→      const lines = before.split('\n')
524→      const currentLine = lines[lines.length - 1]
525→      const indent = getIndent(currentLine)
526→
527→      if (e.shiftKey) {
528→        // Dedent
529→        if (indent === 0) return
530→        const newLines = [...lines]
531→        newLines[newLines.length - 1] = '\t'.repeat(indent - 1) + currentLine.slice(indent)
532→        const newBefore = newLines.join('\n')
533→        const newText = newBefore + after
534→        div.innerHTML = toHtml(newText)
535→        onChange(newText)
536→        setOffset(div, newBefore.length)
537→      } else {
538→        // Indent — promote to next outline level
539→        const newIndent = indent + 1
540→        const strippedLine = currentLine.slice(indent)
541→        const allLines = text.split('\n')
542→        const currentLineIndexInAll = before.split('\n').length - 1
543→        const deeperPrefix = getNextPrefix(allLines, currentLineIndexInAll, newIndent)
544→        const existing = OUTLINE_LEVELS[indent % OUTLINE_LEVELS.length]
545→        const mExisting = strippedLine.match(existing.pattern)
546→        const contentAfterPrefix = mExisting ? strippedLine.slice(mExisting[0].length) : strippedLine
547→        const newLines = [...lines]
548→        newLines[newLines.length - 1] = deeperPrefix + contentAfterPrefix
549→        const newBefore = newLines.join('\n')
550→        const newText = newBefore + after
551→        div.innerHTML = toHtml(newText)
552→        onChange(newText)
553→        setOffset(div, newBefore.length)
554→      }
555→    }
556→  }
557→
558→  const activeQuote = popover ? (quotes.find(q => q.id === popover.quoteId) ?? null) : null
559→
560→  return (
561→    <>
562→      <div
563→        ref={divRef}
564→        contentEditable
565→        suppressContentEditableWarning
566→        onInput={handleInput}
567→        onKeyDown={handleKeyDown}
568→        onPaste={handlePaste}
569→        onClick={handleClick}
570→        onDragStart={handleDragStart}
571→        onDragOver={handleDragOver}
572→        onDrop={handleDrop}
573→        className={
574→          className ??
575→          'w-full min-h-[400px] bg-fog-100 rounded-xl border border-fog-300 px-5 py-4 text-sm text-navy-900 leading-relaxed focus:outline-none focus:ring-2 focus:ring-navy-500/20 transition-all font-mono'
576→        }
577→        style={{ whiteSpace: 'pre-wrap', wordBreak: 'break-word' }}
578→      />
579→
580→      {popover && (
581→        <div
582→          ref={popoverRef}
583→          style={{
584→            position: 'fixed',
585→            left: Math.min(popover.x, (typeof window !== 'undefined' ? window.innerWidth : 800) - 280),
586→            top: popover.y,
587→            zIndex: 200,
588→          }}
589→          className="bg-white border border-fog-300 rounded-xl shadow-[0_8px_32px_rgba(14,30,53,0.15)] p-3 w-64"
590→        >
591→          {popover.confirming ? (
592→            <div className="flex flex-col gap-3">
593→              <p className="text-sm text-navy-800 font-medium">Remove this link?</p>
594→              <p className="text-xs text-fog-400 leading-relaxed -mt-1">
595→                The quote in the Quotes tab won&rsquo;t be deleted.
596→              </p>
597→              <div className="flex justify-end gap-2">
598→                <button
599→                  onClick={() => setPopover(p => p ? { ...p, confirming: false } : null)}
600→                  className="text-xs text-fog-500 hover:text-navy-700 px-3 py-1.5 rounded-lg transition-colors"
601→                >
602→                  Cancel
603→                </button>
604→                <button
605→                  onClick={() => handleDeleteChip(popover.quoteId, popover.chipOffset)}
606→                  className="text-xs text-white bg-rose-500 hover:bg-rose-600 px-3 py-1.5 rounded-lg font-medium transition-all"
607→                >
608→                  Remove
609→                </button>
610→              </div>
611→            </div>
612→          ) : activeQuote ? (
613→            <>
614→              <div className="flex items-start justify-between gap-2">
615→                <p className="text-sm text-navy-800 leading-snug italic flex-1">
616→                  &ldquo;{activeQuote.quote_text}&rdquo;
617→                </p>
618→                <button
619→                  onClick={() => setPopover(p => p ? { ...p, confirming: true } : null)}
620→                  className="shrink-0 p-1 text-fog-400 hover:text-rose-500 rounded transition-colors"
621→                  title="Remove link"
622→                >
623→                  <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 16 16" fill="currentColor" className="w-3.5 h-3.5">
624→                    <path fillRule="evenodd" d="M5 3.25V4H2.75a.75.75 0 0 0 0 1.5h.3l.815 8.15A1.5 1.5 0 0 0 5.357 15h5.285a1.5 1.5 0 0 0 1.493-1.35l.815-8.15h.3a.75.75 0 0 0 0-1.5H11v-.75A2.25 2.25 0 0 0 8.75 1h-1.5A2.25 2.25 0 0 0 5 3.25Zm2.25-.75a.75.75 0 0 0-.75.75V4h3v-.75a.75.75 0 0 0-.75-.75h-1.5ZM6.05 6a.75.75 0 0 1 .787.713l.275 5.5a.75.75 0 0 1-1.498.075l-.275-5.5A.75.75 0 0 1 6.05 6Zm3.9 0a.75.75 0 0 1 .712.787l-.275 5.5a.75.75 0 0 1-1.498-.075l.275-5.5a.75.75 0 0 1 .786-.711Z" clipRule="evenodd" />
625→                  </svg>
626→                </button>
627→              </div>
628→              {activeQuote.page_number != null && (
629→                <p className="text-xs text-fog-400 mt-1.5">p. {activeQuote.page_number}</p>
630→              )}
631→              {activeQuote.tags.length > 0 && (
632→                <div className="flex flex-wrap gap-1 mt-2">
633→                  {activeQuote.tags.map(tag => (
634→                    <span
635→                      key={tag}
636→                      className="text-[10px] bg-fog-100 text-fog-600 border border-fog-300 px-1.5 py-0.5 rounded-full"
637→                    >
638→                      {tag}
639→                    </span>
640→                  ))}
641→                </div>
642→              )}
643→            </>
644→          ) : (
645→            <p className="text-xs text-fog-400 italic">Quote not found</p>
646→          )}
647→        </div>
648→      )}
649→    </>
650→  )
651→})
652→
653→export default OutlineEditor
