 69→      html += `<span style="${CHIP_STYLE}" contenteditable="false" draggable="true" data-quote-id="${parts[i]}">Q</span>`
 70→    }
 71→  }
 72→  return html
 73→}
 74→
 75→/**
 76→ * Walk the contenteditable DOM and return the [quote:id] serialized string.
 77→ * <br> → '\n'; chip spans → [quote:id]; browser-inserted DIVs → '\n' prefix.
 78→ */
 79→function toText(root: Node): string {
 80→  let text = ''
 81→  for (const node of root.childNodes) {
 82→    if (node.nodeType === Node.TEXT_NODE) {
 83→      text += node.textContent ?? ''
 84→    } else if (node.nodeType === Node.ELEMENT_NODE) {
 85→      const el = node as HTMLElement
 86→      if (el.dataset.quoteId) {
 87→        text += `[quote:${el.dataset.quoteId}]`
 88→      } else if (el.tagName === 'BR') {
 89→        text += '\n'
 90→      } else if (el.tagName === 'DIV' || el.tagName === 'P') {
 91→        if (node.previousSibling) text += '\n'
 92→        text += toText(el)
 93→      } else {
 94→        text += toText(el)
 95→      }
 96→    }
 97→  }
 98→  return text
 99→}
100→
101→// ── Cursor offset helpers ─────────────────────────────────────────────────────
102→
103→/** Serialized character length of a single DOM node. */
104→function nodeLen(node: Node): number {
105→  if (node.nodeType === Node.TEXT_NODE) return node.textContent?.length ?? 0
106→  const el = node as HTMLElement
107→  if (el.dataset?.quoteId) return `[quote:${el.dataset.quoteId}]`.length
108→  if (el.tagName === 'BR') return 1
109→  let n = 0
110→  for (const child of el.childNodes) n += nodeLen(child)
111→  return n
112→}
113→
114→/** Compute the serialized character offset for a given DOM Range. */
115→function getOffsetFromRange(div: HTMLElement, range: Range): number {
116→  if (range.startContainer === div) {
117→    let off = 0
118→    for (let i = 0; i < range.startOffset; i++) off += nodeLen(div.childNodes[i])
119→    return off
120→  }
121→
122→  let offset = 0
123→  let found = false
124→
125→  function walk(node: Node): void {
126→    if (found) return
127→    if (node === range.startContainer) {
128→      offset += range.startOffset
129→      found = true
130→      return
131→    }
132→    if (node.nodeType === Node.TEXT_NODE) {
133→      offset += node.textContent?.length ?? 0
134→    } else {
135→      const el = node as HTMLElement
136→      if (el.dataset?.quoteId) {
137→        offset += `[quote:${el.dataset.quoteId}]`.length
138→      } else if (el.tagName === 'BR') {
139→        offset += 1
140→      } else {
141→        for (const child of el.childNodes) {
142→          walk(child)
143→          if (found) return
144→        }
145→      }
146→    }
147→  }
148→
149→  for (const child of div.childNodes) {
150→    walk(child)
151→    if (found) break
152→  }
153→  return offset
154→}
155→
156→/**
157→ * Return the cursor's position as an offset in the serialized (text) string.
158→ * Quote chips count as their full [quote:uuid] token length.
159→ */
160→function getOffset(div: HTMLElement): number {
161→  const sel = window.getSelection()
162→  if (!sel || sel.rangeCount === 0) return 0
163→  return getOffsetFromRange(div, sel.getRangeAt(0))
164→}
165→
166→/** Return the serialized character offset marking the start of a given child node. */
167→function getNodeOffset(div: HTMLElement, targetNode: Node): number {
168→  let offset = 0
169→  let found = false
170→
171→  function walk(node: Node): void {
172→    if (found) return
173→    if (node === targetNode) { found = true; return }
174→    if (node.nodeType === Node.TEXT_NODE) {
175→      offset += node.textContent?.length ?? 0
176→    } else {
177→      const el = node as HTMLElement
178→      if (el.dataset?.quoteId) {
179→        offset += `[quote:${el.dataset.quoteId}]`.length
180→      } else if (el.tagName === 'BR') {
181→        offset += 1
182→      } else {
183→        for (const child of el.childNodes) {
184→          walk(child)
185→          if (found) return
186→        }
187→      }
188→    }
189→  }
190→
191→  for (const child of div.childNodes) {
192→    walk(child)
193→    if (found) break
194→  }
195→  return offset
196→}
197→
198→/**
199→ * Place the cursor at the given offset in the serialized string space.
200→ */
201→function setOffset(div: HTMLElement, target: number): void {
202→  let remaining = target
203→  let placed = false
204→
205→  function placeCursor(node: Node, off: number): void {
206→    const range = document.createRange()
207→    range.setStart(node, off)
208→    range.collapse(true)
209→    window.getSelection()?.removeAllRanges()
210→    window.getSelection()?.addRange(range)
211→    placed = true
212→  }
213→
214→  function walk(node: Node): void {
215→    if (placed) return
216→    if (node.nodeType === Node.TEXT_NODE) {
217→      const len = node.textContent?.length ?? 0
218→      if (remaining <= len) { placeCursor(node, remaining); return }
219→      remaining -= len
220→    } else {
221→      const el = node as HTMLElement
222→      if (el.dataset?.quoteId) {
223→        const len = `[quote:${el.dataset.quoteId}]`.length
224→        if (remaining < len) {
225→          const siblings = Array.from(el.parentNode!.childNodes)
226→          placeCursor(el.parentNode!, siblings.indexOf(el as ChildNode) + 1)
227→          return
228→        }
229→        remaining -= len
230→      } else if (el.tagName === 'BR') {
231→        if (remaining === 0) {
232→          placeCursor(div, Array.from(div.childNodes).indexOf(el as ChildNode))
233→          return
234→        }
235→        remaining -= 1
236→      } else {
237→        for (const child of el.childNodes) {
238→          walk(child)
239→          if (placed) return
240→        }
241→      }
242→    }
243→  }
244→
245→  for (const child of div.childNodes) {
246→    walk(child)
247→    if (placed) break
248→  }
249→
250→  if (!placed) {
251→    const range = document.createRange()
252→    range.selectNodeContents(div)
253→    range.collapse(false)
254→    window.getSelection()?.removeAllRanges()
255→    window.getSelection()?.addRange(range)
256→  }
257→}
258→
259→// ── Component ─────────────────────────────────────────────────────────────────
260→
261→const BrainstormEditor = forwardRef<EditorHandle, Props>(function BrainstormEditor(
262→  { value, onChange, className, quotes = [] }: Props,
263→  ref,
264→) {
265→  const divRef = useRef<HTMLDivElement>(null)
266→
267→  useImperativeHandle(ref, () => ({
268→    getCursorOffset: () => divRef.current ? getOffset(divRef.current) : 0,
269→  }))
270→  const popoverRef = useRef<HTMLDivElement>(null)
271→  const [popover, setPopover] = useState<PopoverState | null>(null)
272→
273→  // Sync external value changes → innerHTML only when the content actually differs
274→  useEffect(() => {
275→    const div = divRef.current
276→    if (!div) return
277→    if (toText(div) === value) return
278→    div.innerHTML = toHtml(value)
279→  }, [value])
280→
281→  // Close popover on outside click
282→  useEffect(() => {
283→    if (!popover) return
284→    function onDown(e: MouseEvent) {
285→      if (popoverRef.current && !popoverRef.current.contains(e.target as Node)) {
286→        setPopover(null)
287→      }
288→    }
289→    document.addEventListener('mousedown', onDown)
290→    return () => document.removeEventListener('mousedown', onDown)
291→  }, [popover])
292→
293→  // Serialize DOM → string on every browser-driven mutation
294→  function handleInput() {
295→    const div = divRef.current
296→    if (!div) return
297→    onChange(toText(div))
298→  }
299→
300→  // Intercept paste — insert as plain text only
301→  function handlePaste(e: React.ClipboardEvent<HTMLDivElement>) {
302→    e.preventDefault()
303→    const text = e.clipboardData.getData('text/plain')
304→    document.execCommand('insertText', false, text)
305→  }
306→
307→  // Chip click → popover; other clicks → close popover
308→  function handleClick(e: React.MouseEvent<HTMLDivElement>) {
309→    const target = e.target as HTMLElement
310→    if (target.dataset.quoteId) {
311→      e.preventDefault()
312→      const rect = target.getBoundingClientRect()
313→      const chipOffset = divRef.current ? getNodeOffset(divRef.current, target) : 0
314→      setPopover({ quoteId: target.dataset.quoteId, chipOffset, x: rect.left, y: rect.bottom + 6, confirming: false })
315→    } else {
316→      setPopover(null)
317→    }
318→  }
319→
320→  // Drag Q chip to reorder
321→  function handleDragStart(e: React.DragEvent<HTMLDivElement>) {
322→    const target = e.target as HTMLElement
323→    if (target.dataset?.quoteId) {
324→      e.dataTransfer.setData('text/x-quote-id', target.dataset.quoteId)
325→      e.dataTransfer.effectAllowed = 'move'
326→    }
327→  }
328→
329→  function handleDragOver(e: React.DragEvent<HTMLDivElement>) {
330→    if (e.dataTransfer.types.includes('text/x-quote-id')) {
331→      e.preventDefault()
332→      e.dataTransfer.dropEffect = 'move'
333→    }
334→  }
335→
336→  function handleDrop(e: React.DragEvent<HTMLDivElement>) {
337→    const quoteId = e.dataTransfer.getData('text/x-quote-id')
338→    if (!quoteId || !divRef.current) return
339→    e.preventDefault()
340→    const div = divRef.current
341→    const text = toText(div)
342→    const token = `[quote:${quoteId}]`
343→    const originalPos = text.indexOf(token)
344→    if (originalPos === -1) return
345→
346→    // Resolve drop caret position from mouse coordinates
347→    let dropRange: Range | null = null
348→    if (typeof document.caretRangeFromPoint === 'function') {
349→      dropRange = document.caretRangeFromPoint(e.clientX, e.clientY)
350→    } else {
351→      type CaretPos = { offsetNode: Node; offset: number }
352→      const pos = (document as unknown as { caretPositionFromPoint?: (x: number, y: number) => CaretPos | null })
353→        .caretPositionFromPoint?.(e.clientX, e.clientY) ?? null
354→      if (pos) {
355→        dropRange = document.createRange()
356→        dropRange.setStart(pos.offsetNode, pos.offset)
357→      }
358→    }
359→    if (!dropRange) return
360→
361→    let dropOffset = getOffsetFromRange(div, dropRange)
362→    // Remove chip from serialized text, then adjust drop offset
363→    const textWithout = text.slice(0, originalPos) + text.slice(originalPos + token.length)
364→    if (dropOffset > originalPos) {
365→      dropOffset = Math.max(originalPos, dropOffset - token.length)
366→    }
367→    dropOffset = Math.max(0, Math.min(dropOffset, textWithout.length))
368→    const newText = textWithout.slice(0, dropOffset) + token + textWithout.slice(dropOffset)
369→    div.innerHTML = toHtml(newText)
370→    onChange(newText)
371→    setOffset(div, dropOffset + token.length)
372→  }
373→
374→  // Remove only the specific chip that was clicked (matched by offset, falling back to first occurrence)
375→  function handleDeleteChip(quoteId: string, chipOffset: number) {
376→    const div = divRef.current
377→    if (!div) return
378→    const text = toText(div)
379→    const token = `[quote:${quoteId}]`
380→    const pos = text.slice(chipOffset, chipOffset + token.length) === token
381→      ? chipOffset
382→      : text.indexOf(token)
383→    if (pos === -1) { setPopover(null); return }
384→    const newText = text.slice(0, pos) + text.slice(pos + token.length)
385→    div.innerHTML = toHtml(newText)
386→    onChange(newText)
387→    setPopover(null)
388→  }
389→
390→  // Enter inserts a literal newline (prevents browser from wrapping in <div>).
391→  // Tab inserts a literal tab character for indentation.
392→  function handleKeyDown(e: React.KeyboardEvent<HTMLDivElement>) {
393→    const div = divRef.current
394→    if (!div) return
395→
396→    if (e.key === 'Enter' && !e.shiftKey) {
397→      e.preventDefault()
398→      const text = toText(div)
399→      const pos = getOffset(div)
400→      const newText = text.slice(0, pos) + '\n' + text.slice(pos)
401→      div.innerHTML = toHtml(newText)
402→      onChange(newText)
403→      setOffset(div, pos + 1)
404→      return
405→    }
406→
407→    if (e.key === 'Tab') {
408→      e.preventDefault()
409→      const text = toText(div)
410→      const pos = getOffset(div)
411→      const newText = text.slice(0, pos) + '\t' + text.slice(pos)
412→      div.innerHTML = toHtml(newText)
413→      onChange(newText)
414→      setOffset(div, pos + 1)
415→    }
416→  }
417→
418→  const activeQuote = popover ? (quotes.find(q => q.id === popover.quoteId) ?? null) : null
419→
420→  return (
421→    <>
422→      <div
423→        ref={divRef}
424→        contentEditable
425→        suppressContentEditableWarning
426→        onInput={handleInput}
427→        onKeyDown={handleKeyDown}
428→        onPaste={handlePaste}
429→        onClick={handleClick}
430→        onDragStart={handleDragStart}
431→        onDragOver={handleDragOver}
432→        onDrop={handleDrop}
433→        className={
434→          className ??
435→          'w-full min-h-[400px] bg-fog-100 rounded-xl border border-fog-300 px-5 py-4 text-sm text-navy-900 leading-relaxed focus:outline-none focus:ring-2 focus:ring-navy-500/20 transition-all'
436→        }
437→        style={{ whiteSpace: 'pre-wrap', wordBreak: 'break-word' }}
438→      />
439→
440→      {popover && (
441→        <div
442→          ref={popoverRef}
443→          style={{
444→            position: 'fixed',
445→            left: Math.min(popover.x, (typeof window !== 'undefined' ? window.innerWidth : 800) - 280),
446→            top: popover.y,
447→            zIndex: 200,
448→          }}
449→          className="bg-white border border-fog-300 rounded-xl shadow-[0_8px_32px_rgba(14,30,53,0.15)] p-3 w-64"
450→        >
451→          {popover.confirming ? (
452→            <div className="flex flex-col gap-3">
453→              <p className="text-sm text-navy-800 font-medium">Remove this link?</p>
454→              <p className="text-xs text-fog-400 leading-relaxed -mt-1">
455→                The quote in the Quotes tab won&rsquo;t be deleted.
456→              </p>
457→              <div className="flex justify-end gap-2">
458→                <button
459→                  onClick={() => setPopover(p => p ? { ...p, confirming: false } : null)}
460→                  className="text-xs text-fog-500 hover:text-navy-700 px-3 py-1.5 rounded-lg transition-colors"
461→                >
462→                  Cancel
463→                </button>
464→                <button
465→                  onClick={() => handleDeleteChip(popover.quoteId, popover.chipOffset)}
466→                  className="text-xs text-white bg-rose-500 hover:bg-rose-600 px-3 py-1.5 rounded-lg font-medium transition-all"
467→                >
468→                  Remove
469→                </button>
470→              </div>
471→            </div>
472→          ) : activeQuote ? (
473→            <>
474→              <div className="flex items-start justify-between gap-2">
475→                <p className="text-sm text-navy-800 leading-snug italic flex-1">
476→                  &ldquo;{activeQuote.quote_text}&rdquo;
477→                </p>
478→                <button
479→                  onClick={() => setPopover(p => p ? { ...p, confirming: true } : null)}
480→                  className="shrink-0 p-1 text-fog-400 hover:text-rose-500 rounded transition-colors"
481→                  title="Remove link"
482→                >
483→                  <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 16 16" fill="currentColor" className="w-3.5 h-3.5">
484→                    <path fillRule="evenodd" d="M5 3.25V4H2.75a.75.75 0 0 0 0 1.5h.3l.815 8.15A1.5 1.5 0 0 0 5.357 15h5.285a1.5 1.5 0 0 0 1.493-1.35l.815-8.15h.3a.75.75 0 0 0 0-1.5H11v-.75A2.25 2.25 0 0 0 8.75 1h-1.5A2.25 2.25 0 0 0 5 3.25Zm2.25-.75a.75.75 0 0 0-.75.75V4h3v-.75a.75.75 0 0 0-.75-.75h-1.5ZM6.05 6a.75.75 0 0 1 .787.713l.275 5.5a.75.75 0 0 1-1.498.075l-.275-5.5A.75.75 0 0 1 6.05 6Zm3.9 0a.75.75 0 0 1 .712.787l-.275 5.5a.75.75 0 0 1-1.498-.075l.275-5.5a.75.75 0 0 1 .786-.711Z" clipRule="evenodd" />
485→                  </svg>
486→                </button>
487→              </div>
488→              {activeQuote.page_number != null && (
489→                <p className="text-xs text-fog-400 mt-1.5">p. {activeQuote.page_number}</p>
490→              )}
491→              {activeQuote.tags.length > 0 && (
492→                <div className="flex flex-wrap gap-1 mt-2">
493→                  {activeQuote.tags.map(tag => (
494→                    <span
495→                      key={tag}
496→                      className="text-[10px] bg-fog-100 text-fog-600 border border-fog-300 px-1.5 py-0.5 rounded-full"
497→                    >
498→                      {tag}
499→                    </span>
500→                  ))}
501→                </div>
502→              )}
503→            </>
504→          ) : (
505→            <p className="text-xs text-fog-400 italic">Quote not found</p>
506→          )}
507→        </div>
508→      )}
509→    </>
510→  )
511→})
512→
513→export default BrainstormEditor
