                    >
                      {tag}
                    </span>
                  ))}
                </div>
              )}
            </>
          ) : (
            <p className="text-xs text-fog-400 italic">Quote not found</p>
          )}
        </div>
      )}
    </>
  )
})

export default BrainstormEditor

